        CONSTRAINT "PK_SoftwareRequests" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_SoftwareRequests_Software_SoftwareId" FOREIGN KEY ("SoftwareId") REFERENCES "Software" ("Id") ON DELETE RESTRICT,
        CONSTRAINT "FK_SoftwareRequests_Users_ReviewedByUserId" FOREIGN KEY ("ReviewedByUserId") REFERENCES "Users" ("Id") ON DELETE SET NULL,
        CONSTRAINT "FK_SoftwareRequests_Users_UserId" FOREIGN KEY ("UserId") REFERENCES "Users" ("Id") ON DELETE RESTRICT
    );
    END IF;
END $EF$;

