DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20251014161408_InitialCreate') THEN
    PERFORM setval(
        pg_get_serial_sequence('"Rooms"', 'Id'),
        GREATEST(
            (SELECT MAX("Id") FROM "Rooms") + 1,
            nextval(pg_get_serial_sequence('"Rooms"', 'Id'))),
        false);
    PERFORM setval(
        pg_get_serial_sequence('"Users"', 'Id'),
        GREATEST(
            (SELECT MAX("Id") FROM "Users") + 1,
            nextval(pg_get_serial_sequence('"Users"', 'Id'))),
        false);
    END IF;
END $EF$;

